/**
 * Accept a team invitation
 */
export const acceptTeamInvitationFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => acceptTeamInvitationSchema.parse(data))
  .handler(async ({ data }) => {
    const session = await getSessionFromCookie()

    if (!session) {
      throw new Error("NOT_AUTHORIZED: Not authenticated")
    }

    const db = getDb()
    const MAX_TEAMS_JOINED_PER_USER = 100

    // Find the invitation by token
    const invitation = await db.query.teamInvitationTable.findFirst({
      where: eq(teamInvitationTable.token, data.token),
    })

    if (!invitation) {
      throw new Error("NOT_FOUND: Invitation not found")
    }

    // Check if invitation has expired
    if (invitation.expiresAt && new Date(invitation.expiresAt) < new Date()) {
      throw new Error("Invitation has expired")
    }

    // Check if invitation was already accepted
    if (invitation.acceptedAt) {
      throw new Error("CONFLICT: Invitation has already been accepted")
    }

    // Log email mismatch for tracking, but allow the operation to proceed
    // The acceptedBy field tracks who actually accepted regardless of invite email
    if (session.user.email?.toLowerCase() !== invitation.email?.toLowerCase()) {
      console.log(
        `Team invite email mismatch: invited=${invitation.email}, acceptedBy=${session.user.email}`,
      )
    }

    // Check if user is already a member
    const existingMembership = await db.query.teamMembershipTable.findFirst({
      where: and(
        eq(teamMembershipTable.teamId, invitation.teamId),
        eq(teamMembershipTable.userId, session.userId),
      ),
    })

    if (existingMembership) {
      // Mark invitation as accepted
      await db
        .update(teamInvitationTable)
        .set({
          acceptedAt: new Date(),
          acceptedBy: session.userId,
          updatedAt: new Date(),
        })
        .where(eq(teamInvitationTable.id, invitation.id))

      throw new Error("CONFLICT: You are already a member of this team")
    }

    // Check if user has reached their team joining limit
    const teamsCountResult = await db
      .select({ value: count() })
      .from(teamMembershipTable)
      .where(eq(teamMembershipTable.userId, session.userId))

    const teamsJoined = teamsCountResult[0]?.value || 0

    if (teamsJoined >= MAX_TEAMS_JOINED_PER_USER) {
      throw new Error(
        `FORBIDDEN: You have reached the limit of ${MAX_TEAMS_JOINED_PER_USER} teams you can join.`,
      )
    }

    // Get team from invitation to check type and validate requirements
    const team = await db.query.teamTable.findFirst({
      where: eq(teamTable.id, invitation.teamId),
    })
    if (!team) {
      throw new Error("NOT_FOUND: Team not found")
    }

    // Validate required waivers and questions before accepting
    // (only when there's no pending data from guest form already)
    if (
      team.type === TEAM_TYPE_ENUM.COMPETITION_TEAM &&
      team.competitionMetadata
    ) {
      let hasPendingData = false
      if (invitation.metadata) {
        try {
          const meta = JSON.parse(invitation.metadata) as Record<
            string,
            unknown
          >
          hasPendingData = !!(
            (Array.isArray(meta.pendingAnswers) &&
              meta.pendingAnswers.length > 0) ||
            (Array.isArray(meta.pendingSignatures) &&
              meta.pendingSignatures.length > 0)
          )
        } catch {
          // Invalid JSON, ignore
        }
      }

      if (!hasPendingData) {
        try {
          const compMeta = JSON.parse(team.competitionMetadata) as {
            competitionId?: string
          }
          if (compMeta.competitionId) {
            // Look up competition's groupId for series-level questions
            const [comp] = await db
              .select({ groupId: competitionsTable.groupId })
              .from(competitionsTable)
              .where(eq(competitionsTable.id, compMeta.competitionId))

            // Validate required questions (competition-specific + series-level)
            const questionConditions = [
              and(
                eq(
                  competitionRegistrationQuestionsTable.competitionId,
                  compMeta.competitionId,
                ),
                eq(competitionRegistrationQuestionsTable.required, true),
              ),
            ]
            if (comp?.groupId) {
              questionConditions.push(
                and(
                  eq(
                    competitionRegistrationQuestionsTable.groupId,
                    comp.groupId,
                  ),
                  eq(competitionRegistrationQuestionsTable.required, true),
                ),
              )
            }

            const requiredQuestions =
              await db.query.competitionRegistrationQuestionsTable.findMany({
                where: or(...questionConditions),
              })

            const teammateRequiredQuestions = requiredQuestions.filter(
              (q) => q.forTeammates,
            )

            if (teammateRequiredQuestions.length > 0) {
              const answeredIds = new Set(
                (data.answers || []).map((a) => a.questionId),
              )
              const unanswered = teammateRequiredQuestions.filter(
                (q) => !answeredIds.has(q.id),
              )
              if (unanswered.length > 0) {
                throw new Error(
                  "Please answer all required questions before accepting the invitation",
                )
              }
              // Validate non-empty answers
              for (const q of teammateRequiredQuestions) {
                const answer = (data.answers || []).find(
                  (a) => a.questionId === q.id,
                )
                if (!answer || answer.answer.trim() === "") {
                  throw new Error(
                    "Please answer all required questions before accepting the invitation",
                  )
                }
              }
            }

            // Validate required waivers
            const requiredWaivers = await db.query.waiversTable.findMany({
              where: and(
                eq(waiversTable.competitionId, compMeta.competitionId),
                eq(waiversTable.required, true),
              ),
              columns: { id: true },
            })

            if (requiredWaivers.length > 0) {
              // Check if user already has signatures for these waivers
              const requiredWaiverIds = requiredWaivers.map((w) => w.id)
              const existingSignatures =
                await db.query.waiverSignaturesTable.findMany({
                  where: and(
                    inArray(waiverSignaturesTable.waiverId, requiredWaiverIds),
                    eq(waiverSignaturesTable.userId, session.userId),
                  ),
                  columns: { waiverId: true },
                })
              const existingSignatureWaiverIds = new Set(
                existingSignatures.map((s) => s.waiverId),
              )

              const signedIds = new Set(
                (data.signatures || []).map((s) => s.waiverId),
              )
              const unsignedWaivers = requiredWaivers.filter(
                (w) =>
                  !signedIds.has(w.id) && !existingSignatureWaiverIds.has(w.id),
              )
              if (unsignedWaivers.length > 0) {
                throw new Error(
                  "Please sign all required waivers before accepting the invitation",
                )
              }
            }
          }
        } catch (e) {
          // Re-throw validation errors, ignore JSON parse errors
          if (e instanceof Error && !e.message.includes("JSON")) {
            throw e
          }
        }
      }
    }

    // Add user to the team
    await db.insert(teamMembershipTable).values({
      teamId: invitation.teamId,
      userId: session.userId,
      roleId: invitation.roleId,
      isSystemRole: invitation.isSystemRole,
      invitedBy: invitation.invitedBy ?? undefined,
      invitedAt: invitation.createdAt
        ? new Date(invitation.createdAt)
        : new Date(),
      joinedAt: new Date(),
      isActive: true,
      metadata: invitation.metadata ?? undefined,
    })

    // Mark invitation as accepted (with account)
    await db
      .update(teamInvitationTable)
      .set({
        acceptedAt: new Date(),
        acceptedBy: session.userId,
        status: INVITATION_STATUS.ACCEPTED,
        updatedAt: new Date(),
      })
      .where(eq(teamInvitationTable.id, invitation.id))

    // Update the user's session to include this team
    await updateAllSessionsOfUser(session.userId)

    // Handle competition_team type - also add user to competition_event team
    let registrationId: string | null = null
    let competitionId: string | null = null
    let competitionName: string | null = null
    let competitionSlug: string | null = null
    let divisionName: string | null = null
    let hasWaivers = false

    if (
      team.type === TEAM_TYPE_ENUM.COMPETITION_TEAM &&
      team.competitionMetadata
    ) {
      try {
        const metadata = JSON.parse(team.competitionMetadata) as {
          competitionId?: string
          divisionId?: string
        }
        if (metadata.competitionId) {
          competitionId = metadata.competitionId

          // Add to competition event team
          const competition = await db.query.competitionsTable.findFirst({
            where: eq(competitionsTable.id, metadata.competitionId),
          })

          if (competition) {
            competitionName = competition.name
            competitionSlug = competition.slug

            // Check if user is already a member
            const existingEventMembership =
              await db.query.teamMembershipTable.findFirst({
                where: and(
                  eq(teamMembershipTable.teamId, competition.competitionTeamId),
                  eq(teamMembershipTable.userId, session.userId),
                ),
              })

            if (!existingEventMembership) {
              await db.insert(teamMembershipTable).values({
                teamId: competition.competitionTeamId,
                userId: session.userId,
                roleId: SYSTEM_ROLES_ENUM.MEMBER,
                isSystemRole: true,
                joinedAt: new Date(),
                isActive: true,
              })
            }

            // Find the registration for this team
            const registration =
              await db.query.competitionRegistrationsTable.findFirst({
                where: and(
                  eq(
                    competitionRegistrationsTable.eventId,
                    metadata.competitionId,
                  ),
                  eq(competitionRegistrationsTable.athleteTeamId, team.id),
                ),
                with: {
                  division: {
                    columns: { label: true },
                  },
                },
              })

            if (registration) {
              registrationId = registration.id
              const div = Array.isArray(registration.division)
                ? registration.division[0]
                : registration.division
              divisionName = div?.label || null
            }

            // Check if competition has waivers
            const waivers = await db.query.waiversTable.findMany({
              where: eq(waiversTable.competitionId, metadata.competitionId),
              columns: { id: true },
            })
            hasWaivers = waivers.length > 0

            // Clear from pendingTeammates on the registration
            if (session.user.email) {
              const registrations =
                await db.query.competitionRegistrationsTable.findMany({
                  where: eq(
                    competitionRegistrationsTable.eventId,
                    metadata.competitionId,
                  ),
                  columns: {
                    id: true,
                    pendingTeammates: true,
                  },
                })

              for (const reg of registrations) {
                if (!reg.pendingTeammates) continue

                try {
                  const pending = JSON.parse(reg.pendingTeammates) as Array<{
                    email: string
                    affiliateName?: string | null
                  }>
                  const updatedPending = pending.filter(
                    (t) =>
                      t.email.toLowerCase() !==
                      session.user.email?.toLowerCase(),
                  )

                  if (updatedPending.length !== pending.length) {
                    await db
                      .update(competitionRegistrationsTable)
                      .set({
                        pendingTeammates:
                          updatedPending.length > 0
                            ? JSON.stringify(updatedPending)
                            : null,
                      })
                      .where(eq(competitionRegistrationsTable.id, reg.id))
                    break
                  }
                } catch {
                  // Ignore JSON parse errors
                }
              }
            }

            // Merge answers from request data AND pending metadata
            let allAnswers = data.answers || []

            // Check for pending answers in invitation metadata (from guest form)
            if (invitation.metadata) {
              try {
                const inviteMetadata = JSON.parse(
                  invitation.metadata,
                ) as Record<string, unknown>
                if (Array.isArray(inviteMetadata.pendingAnswers)) {
                  const pendingAnswers =
                    inviteMetadata.pendingAnswers as PendingInviteAnswer[]
                  // Merge pending answers (pending takes precedence if duplicate)
                  const answerMap = new Map<
                    string,
                    { questionId: string; answer: string }
                  >()
                  for (const a of allAnswers) {
                    answerMap.set(a.questionId, a)
                  }
                  for (const a of pendingAnswers) {
                    answerMap.set(a.questionId, a)
                  }
                  allAnswers = Array.from(answerMap.values())
                }
              } catch {
                // Invalid JSON, ignore
              }
            }

            // Store teammate registration answers if provided
            if (allAnswers.length > 0 && registrationId) {
              // Batch fetch existing answers for this user/registration
              const questionIds = allAnswers.map((a) => a.questionId)
              const existingAnswers =
                await db.query.competitionRegistrationAnswersTable.findMany({
                  where: and(
                    inArray(
                      competitionRegistrationAnswersTable.questionId,
                      questionIds,
                    ),
                    eq(
                      competitionRegistrationAnswersTable.registrationId,
                      registrationId,
                    ),
                    eq(
                      competitionRegistrationAnswersTable.userId,
                      session.userId,
                    ),
                  ),
                  columns: { id: true, questionId: true },
                })
              const existingAnswerMap = new Map(
                existingAnswers.map((a) => [a.questionId, a.id]),
              )

              const newAnswers: Array<{
                questionId: string
                registrationId: string
                userId: string
                answer: string
              }> = []

              for (const answerData of allAnswers) {
                const existingId = existingAnswerMap.get(answerData.questionId)
                if (existingId) {
                  // Update existing answer
                  await db
                    .update(competitionRegistrationAnswersTable)
                    .set({
                      answer: answerData.answer,
                      updatedAt: new Date(),
                    })
                    .where(
                      eq(competitionRegistrationAnswersTable.id, existingId),
                    )
                } else {
                  newAnswers.push({
                    questionId: answerData.questionId,
                    registrationId: registrationId,
                    userId: session.userId,
                    answer: answerData.answer,
                  })
                }
              }

              // Batch insert new answers
              if (newAnswers.length > 0) {
                await db
                  .insert(competitionRegistrationAnswersTable)
                  .values(newAnswers)
              }
            }

            // Collect all waiver IDs to check for existing signatures in one query
            const allWaiverIds = [
              ...(data.signatures || []).map((s) => s.waiverId),
            ]

            // Parse pending signatures from invitation metadata
            let inviteMetadata: Record<string, unknown> | null = null
            let pendingSignatures: PendingWaiverSignature[] = []

            if (invitation.metadata && registrationId) {
              try {
                inviteMetadata = JSON.parse(invitation.metadata) as Record<
                  string,
                  unknown
                >
                if (Array.isArray(inviteMetadata.pendingSignatures)) {
                  pendingSignatures =
                    inviteMetadata.pendingSignatures as PendingWaiverSignature[]
                  allWaiverIds.push(...pendingSignatures.map((s) => s.waiverId))
                }
              } catch {
                // Invalid JSON, ignore
              }
            }

            // Batch check existing signatures for all waivers at once
            let existingWaiverIds = new Set<string>()
            if (allWaiverIds.length > 0 && registrationId) {
              const uniqueWaiverIds = [...new Set(allWaiverIds)]
              const existingSigs =
                await db.query.waiverSignaturesTable.findMany({
                  where: and(
                    inArray(waiverSignaturesTable.waiverId, uniqueWaiverIds),
                    eq(waiverSignaturesTable.userId, session.userId),
                  ),
                  columns: { waiverId: true },
                })
              existingWaiverIds = new Set(existingSigs.map((s) => s.waiverId))
            }

            // Store waiver signatures submitted by authenticated user
            if (
              data.signatures &&
              data.signatures.length > 0 &&
              registrationId
            ) {
              const newSigs = data.signatures
                .filter((s) => !existingWaiverIds.has(s.waiverId))
                .map((sigData) => ({
                  waiverId: sigData.waiverId,
                  userId: session.userId,
                  signedAt: new Date(sigData.signedAt),
                  registrationId: registrationId!,
                }))
              if (newSigs.length > 0) {
                await db.insert(waiverSignaturesTable).values(newSigs)
              }
            }

            // Transfer pending waiver signatures from invitation metadata
            if (pendingSignatures.length > 0 && registrationId) {
              const newPendingSigs = pendingSignatures
                .filter((s) => !existingWaiverIds.has(s.waiverId))
                .map((sigData) => ({
                  waiverId: sigData.waiverId,
                  userId: session.userId,
                  signedAt: new Date(sigData.signedAt),
                  registrationId: registrationId!,
                }))
              if (newPendingSigs.length > 0) {
                await db.insert(waiverSignaturesTable).values(newPendingSigs)
              }
            }

            // Transfer organizer-set affiliate (if any) onto the registration
            // metadata, keyed by this newly-joined user's id.
            if (
              inviteMetadata &&
              registrationId &&
              typeof inviteMetadata.affiliateName === "string" &&
              inviteMetadata.affiliateName.trim().length > 0
            ) {
              const affiliateName = inviteMetadata.affiliateName.trim()
              const reg =
                await db.query.competitionRegistrationsTable.findFirst({
                  where: eq(competitionRegistrationsTable.id, registrationId),
                  columns: { metadata: true },
                })
              let regMetadata: Record<string, unknown> = {}
              if (reg?.metadata) {
                try {
                  regMetadata = JSON.parse(reg.metadata) as Record<
                    string,
                    unknown
                  >
                } catch {
                  regMetadata = {}
                }
              }
              if (
                !regMetadata.affiliates ||
                typeof regMetadata.affiliates !== "object"
              ) {
                regMetadata.affiliates = {}
              }
              ;(regMetadata.affiliates as Record<string, string>)[
                session.userId
              ] = affiliateName

              await db
                .update(competitionRegistrationsTable)
                .set({
                  metadata: JSON.stringify(regMetadata),
                  updatedAt: new Date(),
                })
                .where(eq(competitionRegistrationsTable.id, registrationId))

              if (affiliateName.toLowerCase() !== "independent") {
                await db
                  .insert(affiliatesTable)
                  .values({ name: affiliateName })
                  .onDuplicateKeyUpdate({ set: { name: sql`name` } })
              }
            }

            // Clear pending data from metadata now that it's transferred
            if (inviteMetadata && registrationId) {
              delete inviteMetadata.pendingAnswers
              delete inviteMetadata.pendingSignatures
              delete inviteMetadata.submittedAt
              delete inviteMetadata.affiliateName

              await db
                .update(teamInvitationTable)
                .set({
                  metadata:
                    Object.keys(inviteMetadata).length > 0
                      ? JSON.stringify(inviteMetadata)
                      : null,
                })
                .where(eq(teamInvitationTable.id, invitation.id))
            }
          }
        }
      } catch {
        // Ignore JSON parse errors
      }
    }

    return {
      success: true,
      teamId: invitation.teamId,
      teamSlug: team.slug,
      teamName: team.name,
      registrationId,
      competitionId,
      competitionName,
      competitionSlug,
      divisionName,
      hasWaivers,
    }
  })

/**
 * Accept a direct volunteer invitation with additional volunteer data
 */
export const acceptVolunteerInviteFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => acceptVolunteerInviteSchema.parse(data))
  .handler(async ({ data }) => {
    const session = await getSessionFromCookie()
    if (!session) {
      throw new Error("NOT_AUTHORIZED: Not authenticated")
    }

    const db = getDb()
    const MAX_TEAMS_JOINED_PER_USER = 100

    // Find the invitation by token
    const invitation = await db.query.teamInvitationTable.findFirst({
      where: eq(teamInvitationTable.token, data.token),
    })

    if (!invitation) {
      throw new Error("NOT_FOUND: Invitation not found")
    }

    // Verify this is a volunteer invitation
    if (
      invitation.roleId !== SYSTEM_ROLES_ENUM.VOLUNTEER ||
      invitation.isSystemRole !== true
    ) {
      throw new Error("This is not a volunteer invitation")
    }

    // Check if invitation has expired
    if (invitation.expiresAt && new Date(invitation.expiresAt) < new Date()) {
      throw new Error("Invitation has expired")
    }

    // Check if invitation was already accepted
    if (invitation.acceptedAt) {
      throw new Error("CONFLICT: Invitation has already been accepted")
    }

    // Log email mismatch for tracking, but allow the operation to proceed
    // The acceptedBy field tracks who actually accepted regardless of invite email
    if (session.user.email?.toLowerCase() !== invitation.email?.toLowerCase()) {
      console.log(
        `Volunteer invite email mismatch: invited=${invitation.email}, acceptedBy=${session.user.email}`,
      )
    }

    // Check if user is already a member
    const existingMembership = await db.query.teamMembershipTable.findFirst({
      where: and(
        eq(teamMembershipTable.teamId, invitation.teamId),
        eq(teamMembershipTable.userId, session.userId),
      ),
    })

    if (existingMembership) {
      // Mark invitation as accepted
      await db
        .update(teamInvitationTable)
        .set({
          acceptedAt: new Date(),
          acceptedBy: session.userId,
          updatedAt: new Date(),
        })
        .where(eq(teamInvitationTable.id, invitation.id))

      throw new Error(
        "CONFLICT: You are already a volunteer for this competition",
      )
    }

    // Check if user has reached their team joining limit
    const teamsCountResult = await db
      .select({ value: count() })
      .from(teamMembershipTable)
      .where(eq(teamMembershipTable.userId, session.userId))

    const teamsJoined = teamsCountResult[0]?.value || 0

    if (teamsJoined >= MAX_TEAMS_JOINED_PER_USER) {
      throw new Error(
        `FORBIDDEN: You have reached the limit of ${MAX_TEAMS_JOINED_PER_USER} teams you can join.`,
      )
    }

    // Parse existing invitation metadata and merge with user-provided data
    let existingMetadata: Record<string, unknown> = {}
    if (invitation.metadata) {
      try {
        existingMetadata = JSON.parse(invitation.metadata)
      } catch {
        // Invalid JSON, ignore
      }
    }

    // Merge user-provided volunteer data with existing metadata
    const mergedMetadata = {
      ...existingMetadata,
      availability: data.availability,
      availabilityNotes: data.availabilityNotes,
      credentials: data.credentials,
      signupPhone: data.signupPhone,
      // Mark as approved since user is accepting a direct invite
      status: "approved",
    }

    // Add user to the team with merged metadata
    await db.insert(teamMembershipTable).values({
      teamId: invitation.teamId,
      userId: session.userId,
      roleId: invitation.roleId,
      isSystemRole: invitation.isSystemRole,
      invitedBy: invitation.invitedBy ?? undefined,
      invitedAt: invitation.createdAt
        ? new Date(invitation.createdAt)
        : new Date(),
      joinedAt: new Date(),
      isActive: true,
      metadata: JSON.stringify(mergedMetadata),
    })

    // Mark invitation as accepted (with account)
    await db
      .update(teamInvitationTable)
      .set({
        acceptedAt: new Date(),
        acceptedBy: session.userId,
        status: INVITATION_STATUS.ACCEPTED,
        updatedAt: new Date(),
      })
      .where(eq(teamInvitationTable.id, invitation.id))

    // Save registration question answers if provided
    if (data.answers && data.answers.length > 0) {
      for (const { questionId, answer } of data.answers) {
        await db
          .insert(volunteerRegistrationAnswersTable)
          .values({
            questionId,
            invitationId: invitation.id,
            answer,
          })
          .onDuplicateKeyUpdate({ set: { answer } })
      }
    }

    // Update the user's session to include this team
    await updateAllSessionsOfUser(session.userId)

    // Get team to return competition info
    const team = await db.query.teamTable.findFirst({
      where: eq(teamTable.id, invitation.teamId),
    })

    return {
      success: true,
      teamId: invitation.teamId,
      teamSlug: team?.slug,
    }
  })

