              <a
                href={`/sign-in?redirect=/compete/${competition.slug}/volunteer`}
                className="underline"
              >
                Sign in
              </a>{" "}
              to auto-fill your info.
            </p>
          )}
        </form>
      </CardContent>
    </Card>
  )
